<body>
  <main class="app">
    <section class="panel" aria-label="Snake game">
      <div class="header">
        <div class="title-group">
          <h1>Snake</h1>
          <p>Eat food, grow longer, and avoid walls or your own tail.</p>
        </div>
        <div class="scoreboard" aria-label="Scoreboard">
          <div class="stat">
            <span class="stat-label">Score</span>
            <span class="stat-value" id="score">0</span>
          </div>
          <div class="stat">
            <span class="stat-label">Best</span>
            <span class="stat-value" id="best">0</span>
          </div>
        </div>
      </div>

      <div class="game-shell">
        <canvas id="game" width="600" height="600" aria-label="Snake playfield"></canvas>
        <div class="overlay active" id="overlay" aria-live="polite">
          <div class="overlay-card">
            <h2 id="overlay-title">Ready?</h2>
            <p id="overlay-text">Use the arrow keys to start moving.</p>
            <div class="button-row">
              <button id="overlay-button" type="button">Start Game</button>
            </div>
          </div>
        </div>
      </div>
    </section>

    <aside class="sidebar" aria-label="Game details">
      <div class="status-chip" id="status">Waiting to start</div>

      <section class="section">
        <h2>Controls</h2>
        <ul class="list">
          <li>Arrow keys steer the snake.</li>
          <li>Opposite turns are blocked until the next step.</li>
          <li>Press the restart button after a loss.</li>
        </ul>
      </section>

      <section class="section">
        <h2>Goal</h2>
        <p class="hint">Each piece of food adds one point and one segment. Speed ramps up as the score climbs.</p>
      </section>

      <button class="restart-button" id="restart" type="button">Restart</button>
    </aside>
  </main>

  <script>
    (() => {
      const canvas = document.getElementById("game");
      const ctx = canvas.getContext("2d");
      const scoreEl = document.getElementById("score");
      const bestEl = document.getElementById("best");
      const statusEl = document.getElementById("status");
      const overlayEl = document.getElementById("overlay");
      const overlayTitleEl = document.getElementById("overlay-title");
      const overlayTextEl = document.getElementById("overlay-text");
      const overlayButton = document.getElementById("overlay-button");
      const restartButton = document.getElementById("restart");

      const gridSize = 20;
      const boardSize = 20;
      const canvasSize = gridSize * boardSize;
      const initialSpeed = 180;
      const minSpeed = 80;
      const speedStep = 6;

      canvas.width = canvasSize;
      canvas.height = canvasSize;

      const state = {
        snake: [],
        direction: { x: 1, y: 0 },
        nextDirection: { x: 1, y: 0 },
        food: { x: 0, y: 0 },
        score: 0,
        best: Number(localStorage.getItem("snake-best-score") || 0),
        running: false,
        over: false,
        lastTick: 0,
        tickInterval: initialSpeed
      };

      bestEl.textContent = String(state.best);

      function randomCell() {
        return Math.floor(Math.random() * boardSize);
      }

      function updateScore() {
        scoreEl.textContent = String(state.score);
        bestEl.textContent = String(state.best);
      }

      function setStatus(text, className) {
        statusEl.textContent = text;
        statusEl.className = "status-chip" + (className ? " " + className : "");
      }

      function showOverlay(title, text, buttonLabel) {
        overlayTitleEl.textContent = title;
        overlayTextEl.textContent = text;
        overlayButton.textContent = buttonLabel;
        overlayEl.classList.add("active");
      }

      function hideOverlay() {
        overlayEl.classList.remove("active");
      }

      function placeFood() {
        let food;
        do {
          food = { x: randomCell(), y: randomCell() };
        } while (state.snake.some((segment) => segment.x === food.x && segment.y === food.y));
        state.food = food;
      }

      function resetGame() {
        state.snake = [
          { x: 4, y: 10 },
          { x: 3, y: 10 },
          { x: 2, y: 10 }
        ];
        state.direction = { x: 1, y: 0 };
        state.nextDirection = { x: 1, y: 0 };
        state.score = 0;
        state.running = false;
        state.over = false;
        state.lastTick = 0;
        state.tickInterval = initialSpeed;
        placeFood();
        updateScore();
        setStatus("Waiting to start", "");
        showOverlay("Ready?", "Use the arrow keys to start moving.", "Start Game");
        draw();
      }

      function startGame() {
        if (state.over) {
          resetGame();
        }
        if (!state.running) {
          state.running = true;
          state.lastTick = performance.now();
          hideOverlay();
          setStatus("In play", "live");
          window.requestAnimationFrame(loop);
        }
      }

      function endGame() {
        state.running = false;
        state.over = true;
        setStatus("Game over", "ended");
        showOverlay("Game Over", "Final score: " + state.score + ". Press restart to play again.", "Play Again");
      }

      function updateBestScore() {
        if (state.score > state.best) {
          state.best = state.score;
          localStorage.setItem("snake-best-score", String(state.best));
        }
      }

      function handleFood(nextHead) {
        if (nextHead.x === state.food.x && nextHead.y === state.food.y) {
          state.score += 1;
          updateBestScore();
          updateScore();
          state.tickInterval = Math.max(minSpeed, initialSpeed - state.score * speedStep);
          placeFood();
          return true;
        }
        return false;
      }

      function step() {
        state.direction = { ...state.nextDirection };
        const head = state.snake[0];
        const nextHead = {
          x: head.x + state.direction.x,
          y: head.y + state.direction.y
        };

        const hitWall =
          nextHead.x < 0 ||
          nextHead.x >= boardSize ||
          nextHead.y < 0 ||
          nextHead.y >= boardSize;

        const hitSelf = state.snake.some((segment) => segment.x === nextHead.x && segment.y === nextHead.y);

        if (hitWall || hitSelf) {
          endGame();
          draw();
          return;
        }

        state.snake.unshift(nextHead);

        if (!handleFood(nextHead)) {
          state.snake.pop();
        }

        draw();
      }

      function drawGrid() {
        ctx.strokeStyle = "rgba(36, 67, 95, 0.55)";
        ctx.lineWidth = 1;

        for (let index = 1; index < boardSize; index += 1) {
          const position = index * gridSize + 0.5;
          ctx.beginPath();
          ctx.moveTo(position, 0);
          ctx.lineTo(position, canvasSize);
          ctx.stroke();

          ctx.beginPath();
          ctx.moveTo(0, position);
          ctx.lineTo(canvasSize, position);
          ctx.stroke();
        }
      }

      function drawFood() {
        const padding = 4;
        const x = state.food.x * gridSize + padding;
        const y = state.food.y * gridSize + padding;
        const size = gridSize - padding * 2;

        ctx.fillStyle = "#ff8c5a";
        ctx.beginPath();
        ctx.roundRect(x, y, size, size, 6);
        ctx.fill();

        ctx.fillStyle = "rgba(255, 255, 255, 0.18)";
        ctx.beginPath();
        ctx.arc(x + size * 0.38, y + size * 0.34, size * 0.16, 0, Math.PI * 2);
        ctx.fill();
      }

      function drawSnake() {
        state.snake.forEach((segment, index) => {
          const padding = index === 0 ? 2 : 3;
          const x = segment.x * gridSize + padding;
          const y = segment.y * gridSize + padding;
          const size = gridSize - padding * 2;

          ctx.fillStyle = index === 0 ? "#8cffc2" : "#3ce08e";
          ctx.beginPath();
          ctx.roundRect(x, y, size, size, 5);
          ctx.fill();

          if (index === 0) {
            const eyeRadius = 1.8;
            const eyeOffsetX = state.direction.x !== 0 ? size * 0.65 : size * 0.3;
            const eyeOffsetYTop = state.direction.y !== 1 ? size * 0.3 : size * 0.45;
            const eyeOffsetYBottom = state.direction.y !== -1 ? size * 0.7 : size * 0.55;
            const eyeX = state.direction.x === -1 ? x + size * 0.3 : x + eyeOffsetX;

            ctx.fillStyle = "#062513";
            ctx.beginPath();
            ctx.arc(eyeX, y + eyeOffsetYTop, eyeRadius, 0, Math.PI * 2);
            ctx.arc(eyeX, y + eyeOffsetYBottom, eyeRadius, 0, Math.PI * 2);
            ctx.fill();
          }
        });
      }

      function draw() {
        ctx.clearRect(0, 0, canvasSize, canvasSize);

        const background = ctx.createLinearGradient(0, 0, 0, canvasSize);
        background.addColorStop(0, "#102030");
        background.addColorStop(1, "#09121b");
        ctx.fillStyle = background;
        ctx.fillRect(0, 0, canvasSize, canvasSize);

        drawGrid();
        drawFood();
        drawSnake();
      }

      function loop(timestamp) {
        if (!state.running) {
          return;
        }

        if (timestamp - state.lastTick >= state.tickInterval) {
          state.lastTick = timestamp;
          step();
        }

        if (state.running) {
          window.requestAnimationFrame(loop);
        }
      }

      function queueDirection(nextX, nextY) {
        const blocked =
          nextX === -state.direction.x &&
          nextY === -state.direction.y;

        if (blocked) {
          return;
        }

        state.nextDirection = { x: nextX, y: nextY };

        if (!state.running && !state.over) {
          startGame();
        }
      }

      document.addEventListener("keydown", (event) => {
        const keyMap = {
          ArrowUp: [0, -1],
          ArrowDown: [0, 1],
          ArrowLeft: [-1, 0],
          ArrowRight: [1, 0]
        };

        if (keyMap[event.key]) {
          event.preventDefault();
          const [nextX, nextY] = keyMap[event.key];
          queueDirection(nextX, nextY);
          return;
        }

        if ((event.key === " " || event.key === "Enter") && !state.running) {
          event.preventDefault();
          startGame();
        }
      }, { passive: false });

      overlayButton.addEventListener("click", () => {
        if (state.over) {
          resetGame();
        }
        startGame();
      });

      restartButton.addEventListener("click", () => {
        resetGame();
      });

      resetGame();
    })();
  </script>
</body>
